# Category: serverless_security

import logging
import os
import json
import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient, CloudEvent

# Environment variables
AZURE_STORAGE_ACCOUNT_URL = os.environ.get('AZURE_STORAGE_ACCOUNT_URL')
COSMOS_DB_ENDPOINT = os.environ.get('COSMOS_DB_ENDPOINT')
COSMOS_DB_DATABASE_ID = os.environ.get('COSMOS_DB_DATABASE_ID')
COSMOS_DB_CONTAINER_ID = os.environ.get('COSMOS_DB_CONTAINER_ID')
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get('EVENT_GRID_TOPIC_ENDPOINT')

# Initialize clients using Managed Identity (DefaultAzureCredential)
credential = DefaultAzureCredential()

# Blob Service Client
blob_service_client = BlobServiceClient(account_url=AZURE_STORAGE_ACCOUNT_URL, credential=credential)

# Cosmos DB Client
cosmos_client = CosmosClient(url=COSMOS_DB_ENDPOINT, credential=credential)
cosmos_database = cosmos_client.get_database_client(COSMOS_DB_DATABASE_ID)
cosmos_container = cosmos_database.get_container_client(COSMOS_DB_CONTAINER_ID)

# Event Grid Publisher Client
event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

app = func.FunctionApp()

@app.blob_trigger(arg_name="inputblob", path="input-container/{name}",
                  connection="AzureWebJobsStorage") # "AzureWebJobsStorage" connection uses Managed Identity
def ProcessBlobFunction(inputblob: func.InputStream):
    logging.info(f"Python blob trigger function processed blob\n"
                 f"Name: {inputblob.name}\n"
                 f"URI: {inputblob.uri}\n"
                 f"Size: {inputblob.length} Bytes")

    try:
        # Read blob content
        blob_content = inputblob.read().decode('utf-8')
        logging.info(f"Blob content: {blob_content[:100]}...") # Log first 100 chars

        # --- Process the content (simple example: count words) ---
        word_count = len(blob_content.split())
        processing_result = {
            "id": os.path.basename(inputblob.name), # Use blob name as ID
            "blobUri": inputblob.uri,
            "processedTimestamp": f"{os.getenv('WEBSITE_HOSTNAME')} {func.get_invocation_context().invocation_id}",
            "wordCount": word_count,
            "originalBlobName": os.path.basename(inputblob.name)
        }
        logging.info(f"Processing result: {processing_result}")

        # --- Write result to Cosmos DB ---
        cosmos_container.upsert_item(processing_result)
        logging.info(f"Successfully wrote result for '{os.path.basename(inputblob.name)}' to Cosmos DB.")

        # --- Send notification via Event Grid ---
        event_data = {
            "subject": f"/blob/{os.path.basename(inputblob.name)}",
            "eventType": "BlobProcessed",
            "data": {
                "blobUri": inputblob.uri,
                "processedItemId": processing_result["id"],
                "wordCount": word_count,
                "status": "Success"
            },
            "dataVersion": "1.0"
        }
        
        event = CloudEvent(
            source=inputblob.uri,
            type="Blob.Processed",
            data=event_data,
            subject=f"processedBlob/{os.path.basename(inputblob.name)}"
        )
        event_grid_client.send(event)
        logging.info(f"Successfully sent Event Grid notification for '{os.path.basename(inputblob.name)}'.")

    except Exception as e:
        logging.error(f"Error processing blob '{inputblob.name}': {e}")
        # Optionally send a failure notification
        error_event_data = {
            "subject": f"/blob/{os.path.basename(inputblob.name)}",
            "eventType": "BlobProcessingFailed",
            "data": {
                "blobUri": inputblob.uri,
                "errorMessage": str(e),
                "status": "Failure"
            },
            "dataVersion": "1.0"
        }
        error_event = CloudEvent(
            source=inputblob.uri,
            type="Blob.ProcessingFailed",
            data=error_event_data,
            subject=f"failedBlob/{os.path.basename(inputblob.name)}"
        )
        event_grid_client.send(error_event)
        raise # Re-raise the exception to indicate failure to the Function Host